// src/components/LiveMap.jsx
import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

export default function LiveMap({ complaints = [], height = '100%', onPinClick }) {
  const mapContainerRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const markersLayerRef = useRef(null);

  // Nagpur Railway Station Core Coordinates Matrix
  const center = [21.1522, 79.0882];
  const zoom = 16;

  // Status color mapper matching your dashboard logs exactly
  const getStatusColor = (status) => {
    switch (status) {
      case 'NEW': return '#FF1744';         // Red
      case 'ACCEPTED': return '#1565C0';    // Blue
      case 'IN_PROGRESS': return '#AA00FF'; // Purple
      case 'COMPLETED': return '#00E676';   // Green
      default: return '#E65100';            // Amber
    }
  };

  // 1. Initialize Leaflet Map Window on Mount
  useEffect(() => {
    if (!mapContainerRef.current || mapInstanceRef.current) return;

    // Direct targeting to Nagpur Junction
    const map = L.map(mapContainerRef.current, { 
      zoomControl: true, 
      attributionControl: false 
    }).setView(center, zoom);

    // Standard OpenStreetMap Layers
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { 
      maxZoom: 19 
    }).addTo(map);

    // Create a dynamic layer group specifically for the cleaner status dots
    const markersLayer = L.layerGroup().addTo(map);
    
    mapInstanceRef.current = map;
    markersLayerRef.current = markersLayer;

    // Cleanup map context window on unmount
    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
    };
  }, []);

  // 2. Clear and Redraw Pure Dots Node whenever complaints array shifts
  useEffect(() => {
    if (!mapInstanceRef.current || !markersLayerRef.current) return;

    // purane saare pins layer se clear karo
    markersLayerRef.current.clearLayers();

    complaints.forEach((c) => {
      if (!c.lat || !c.lng) return;

      const dotColor = getStatusColor(c.status);

      // Generating custom SVG Glowing Dot Layout (Strictly no emojis)
      const customHtmlIcon = L.divIcon({
        className: 'custom-live-dot',
        html: `
          <div style="position: relative; width: 14px; height: 14px;">
            <div style="position: absolute; width: 30px; height: 30px; background: ${dotColor}; opacity: 0.3; border-radius: 50%; top: -8px; left: -8px; animation: leaflet-ping 1.6s infinite;"></div>
            <div style="width: 14px; height: 14px; background: ${dotColor}; border-radius: 50%; border: 2px solid #fff; box-shadow: 0 2px 6px rgba(0,0,0,0.4);"></div>
          </div>
        `,
        iconSize: [14, 14],
        iconAnchor: [7, 7]
      });

      // Bind dynamic point properties on layer matrix
      const marker = L.marker([c.lat, c.lng], { icon: customHtmlIcon });

      if (onPinClick) {
        marker.on('click', () => onPinClick(c));
      }

      marker.addTo(markersLayerRef.current);
    });
  }, [complaints, onPinClick]);

  return (
    <div style={{ height, width: '100%', position: 'relative', borderRadius: 12, overflow: 'hidden', border: '1px solid #DDE3E9' }}>
      {/* Target Container Map Wrapper */}
      <div ref={mapContainerRef} style={{ width: '100%', height: '100%' }} />

      {/* Embedded CSS for pulsing effect inside Leaflet viewports */}
      <style>{`
        @keyframes leaflet-ping {
          0% { transform: scale(0.4); opacity: 1; }
          100% { transform: scale(2); opacity: 0; }
        }
        .leaflet-div-icon {
          background: transparent !important;
          border: none !important;
        }
      `}</style>
    </div>
  );
}
